INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1066, 187108, 13, 1571, '向日葵', '哦，是这样的吗？没有秋天的预兆，路边梧桐的叶子还来不及变成金色，还来不及铺满走过的路。北风就来了，寒冷来了，冬天来了。。。
<br>    哦，没关系的，不过是少过了一个秋天，少看了一遍落叶的过程，少见了一些秋天的云罢，这些，以后都会有的，在生命中，不只就这一个秋天了吧，虽然我知道，每个都是不同的。
<br>    突然，想起凡高的向日葵，一幅仿画的拼图。一直没机会来拼出一幅完整的画，以为，如果开始了，就不能中途搁下，那些彩色的片断需要仔细地放在合适的位置，需要小心地保存。只有每个位置都正确，没有一片丢失才可成全一幅美丽的，完全的画。见过不少没拼起来的画页，一种是拼了开头便因为缺乏耐心而搁置起来，一种是拼着拼着，便不见了几片，即使是拼完了，也是遗憾，也就放在了一边，还有一种无可奈何的便是就快拼完了，却被一个不小心打翻，之前的辛苦只剩下满目碎片，索性放弃。。。
<br>    花瓶已经在那边了，向日葵呢，夏天也是不远的，我想，它会盛开的吧，在开满凤凰花的日子。。。', '哦，是这样的吗？没有秋天的预兆，路边梧桐的叶子还来不及变成金色，还来不及铺满走过的路。北风就来了，寒冷来了，冬天来了。。。

哦，没关系的，不过是少过了一个秋天，少看了一遍落叶的过程，少见了一些秋天的云罢，这些，以后都会有的，在生命中，不只就这一个秋天了吧，虽然我知道，每个都是不同的。

突然，想起凡高的向日葵，一幅仿画的拼图。一直没机会来拼出一幅完整的画，以为，如果开始了，就不能中途搁下，那些彩色的片断需要仔细地放在合适的位置，需要小心地保存。只有每个位置都正确，没有一片丢失才可成全一幅美丽的，完全的画。见过不少没拼起来的画页，一种是拼了开头便因为缺乏耐心而搁置起来，一种是拼着拼着，便不见了几片，即使是拼完了，也是遗憾，也就放在了一边，还有一种无可奈何的便是就快拼完了，却被一个不小心打翻，之前的辛苦只剩下满目碎片，索性放弃。。。

花瓶已经在那边了，向日葵呢，夏天也是不远的，我想，它会盛开的吧，在开满凤凰花的日子。。。', NULL, '2002-10-24 18:14:00', 0, '20021118131932_bbsid_187108_board_13_74ed81d8ed.html', '20021118131932');
